// Identity Router: determine user tier before any processing.
// Returns tier: 'admin' | 'collaborator' | 'unauthorized'
const update = items[0].json;
const adminId = $env.TELEGRAM_ADMIN_ID?.toString();
const collabId = $env.TELEGRAM_COLLAB_ID?.toString();

const fromId = (
  update.message?.from?.id ||
  update.callback_query?.from?.id
)?.toString();

const chatId = (
  update.message?.chat?.id ||
  update.callback_query?.message?.chat?.id
)?.toString();

let tier = 'unauthorized';
if (fromId === adminId) tier = 'admin';
else if (collabId && fromId === collabId) tier = 'collaborator';

// Extract callback data if this is a confirm/cancel for a pending action
const callbackData = update.callback_query?.data || '';
const isCallback = !!update.callback_query;
const isVoice = !!(update.message?.voice);
const voiceFileId = update.message?.voice?.file_id || null;
const text = update.message?.text || '';

return [{ json: { tier, fromId, chatId, isCallback, isCallbackStr: isCallback ? 'yes' : 'no', callbackData, isVoice, voiceFileId, text } }];

const update = items[0].json;
const { callbackData, chatId, tier } = update;

// Not a confirm/cancel callback — drop silently
if (!callbackData || (!callbackData.startsWith('confirm_') && !callbackData.startsWith('cancel_'))) {
  return [[], []];
}

const parts = callbackData.split('_');
const cbAction = parts[0];
const actionKey = parts.slice(1).join('_');

const sd = $getWorkflowStaticData('global');
const pending = sd.pendingActions?.[actionKey];
if (!pending) {
  // output 1 → Telegram Cancelled (expired)
  return [[], [{ json: { message: '⏰ Acción expirada. Vuelve a enviar el comando.', chatId } }]];
}
delete sd.pendingActions[actionKey];

if (cbAction === 'cancel') {
  // output 1 → Telegram Cancelled
  return [[], [{ json: { message: '❌ Acción cancelada.', chatId } }]];
}

// output 0 → Refresh Beds24 Token → execute
return [[{ json: {
  confirmed:     true,
  action:        pending.action,
  endpoint:      pending.endpoint,
  method:        pending.method,
  payload:       pending.payload,
  beds24Payload: pending.beds24Payload || null,
  chatId,
} }], []];

// Download voice OGG and encode as base64 for Gemini multimodal
const fileInfo = items[0].json;
const filePath = fileInfo.result?.file_path;
if (!filePath) throw new Error('Could not get voice file path from Telegram');

const fileUrl = `https://api.telegram.org/file/bot${$env.TELEGRAM_BOT_TOKEN}/${filePath}`;
const resp = await fetch(fileUrl);
if (!resp.ok) throw new Error('Failed to download voice file');
const buffer = Buffer.from(await resp.arrayBuffer());
const base64Audio = buffer.toString('base64');

const { chatId, tier } = $('Identity Router').first().json;
return [{ json: { base64Audio, mimeType: 'audio/ogg', chatId, tier } }];

// Schema Validator: parse Gemini output and validate before any API call.
// Merge voice/text paths — either node could have fired.
const geminiRaw = items[0].json;
const ctx = $('Identity Router').first().json;


let parsed;
try {
  let rawText = geminiRaw.content?.[0]?.text || '{}';
  // Strip markdown code fences that Claude sometimes wraps JSON in
  rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(rawText);
} catch(e) {
  return [{ json: { validationError: 'Claude returned invalid JSON: ' + e.message, chatId: ctx.chatId } }];
}

// Normalize action names — Claude uses various formats (camelCase, snake_case, with/without prefix)
const actionMap = {
  // camelCase variants
  'getOccupancy': 'beds24.getOccupancy',
  'getPrices': 'beds24.getPrices',
  'get_prices': 'beds24.getPrices',
  'getRates': 'beds24.getPrices',
  'get_rates': 'beds24.getPrices',
  'listBookings': 'beds24.listBookings',
  'getRevenue': 'beds24.getRevenue',
  'blockRoom': 'beds24.blockRoom',
  'updatePrice': 'beds24.updatePrice',
  'cancelBooking': 'beds24.cancelBooking',
  'listReservations': 'tastyigniter.listReservations',
  'checkAvailability': 'tastyigniter.checkAvailability',
  'deleteReservation': 'tastyigniter.deleteReservation',
  'getTicketCounts': 'hievents.getTicketCounts',
  'listEvents': 'hievents.listEvents',
  // snake_case variants
  'get_occupancy': 'beds24.getOccupancy',
  'list_bookings': 'beds24.listBookings',
  'get_revenue': 'beds24.getRevenue',
  'block_room': 'beds24.blockRoom',
  'update_price': 'beds24.updatePrice',
  'cancel_booking': 'beds24.cancelBooking',
  'list_reservations': 'tastyigniter.listReservations',
  'check_availability': 'tastyigniter.checkAvailability',
  'delete_reservation': 'tastyigniter.deleteReservation',
  'get_ticket_counts': 'hievents.getTicketCounts',
  'list_events': 'hievents.listEvents',
};
const rawAction = parsed.action || '';
if (!rawAction.includes('.') && actionMap[rawAction]) {
  parsed.action = actionMap[rawAction];
}
// Also normalize dotted variants with wrong service prefix or casing
const actionNorm = rawAction.split('.').pop();
if (rawAction.includes('.') && actionMap[actionNorm]) {
  parsed.action = actionMap[actionNorm];
}
// Fuzzy fallback: if action still not recognized, match by keyword
const knownActions = Object.values(actionMap).concat([
  'beds24.getOccupancy','beds24.getPrices','beds24.listBookings','beds24.getRevenue',
  'beds24.blockRoom','beds24.updatePrice','beds24.cancelBooking',
  'tastyigniter.listReservations','tastyigniter.checkAvailability',
  'tastyigniter.deleteReservation','hievents.getTicketCounts','hievents.listEvents','unknown'
]);
if (!knownActions.includes(parsed.action)) {
  const a = parsed.action.toLowerCase();
  if      (a.includes('occupan') || a.includes('ocupac'))      parsed.action = 'beds24.getOccupancy';
  else if (a.includes('price') || a.includes('precio') || a.includes('rate') || a.includes('tarifa') || a.includes('coste') || a.includes('cuest')) parsed.action = 'beds24.getPrices';
  else if (a.includes('booking') || a.includes('reserv') && a.includes('beds')) parsed.action = 'beds24.listBookings';
  else if (a.includes('reserv'))   parsed.action = 'tastyigniter.listReservations';
  else if (a.includes('availab') || a.includes('disponib'))    parsed.action = 'tastyigniter.checkAvailability';
  else if (a.includes('ticket') || a.includes('event'))        parsed.action = 'hievents.getTicketCounts';
  else if (a.includes('price') || a.includes('precio'))        parsed.action = 'beds24.updatePrice';
  else if (a.includes('block') || a.includes('bloquea'))       parsed.action = 'beds24.blockRoom';
  else if (a.includes('cancel'))   parsed.action = 'beds24.cancelBooking';
  else    parsed.action = 'unknown';
}


// Hardcode correct Beds24 V2 endpoints — Claude doesn't know exact URLs
const endpointMap = {
  'beds24.getOccupancy':   { endpoint: 'https://beds24.com/api/v2/inventory/rooms/availability?propId=318433', method: 'GET' },
  'beds24.getPrices':     { endpoint: 'https://beds24.com/api/v2/inventory/rooms/availability?propId=318433', method: 'GET' },
  'beds24.listBookings':   { endpoint: 'https://beds24.com/api/v2/bookings?propId=318433', method: 'GET' },
  'beds24.getRevenue':     { endpoint: 'https://beds24.com/api/v2/bookings?propId=318433&status=confirmed', method: 'GET' },
  'beds24.blockRoom':      { endpoint: 'https://beds24.com/api/v2/inventory/rooms/calendar', method: 'POST' },
  'beds24.updatePrice':    { endpoint: 'https://beds24.com/api/v2/inventory/rooms/calendar', method: 'POST' },
  'beds24.cancelBooking':  { endpoint: 'https://beds24.com/api/v2/bookings/' + (parsed.payload?.bookingId || ''), method: 'DELETE' },
  'tastyigniter.listReservations':   { endpoint: 'https://restaurant.hobbitonranch.com/api/internal/reservations', method: 'GET' },
  'tastyigniter.checkAvailability':  { endpoint: 'https://restaurant.hobbitonranch.com/api/internal/availability', method: 'GET' },
  'tastyigniter.deleteReservation':  { endpoint: 'https://restaurant.hobbitonranch.com/api/internal/reservations/' + (parsed.payload?.reservationId || ''), method: 'DELETE' },
  'hievents.getTicketCounts': { endpoint: 'https://events.hobbitonranch.com/api/v1/events', method: 'GET' },
  'hievents.listEvents':      { endpoint: 'https://events.hobbitonranch.com/api/v1/events', method: 'GET' },
};
if (endpointMap[parsed.action]) {
  parsed.endpoint = endpointMap[parsed.action].endpoint;
  parsed.method   = endpointMap[parsed.action].method;
}
// Append date range to Beds24 availability endpoint if payload contains a date
if ((parsed.action === 'beds24.getOccupancy' || parsed.action === 'beds24.getPrices') && parsed.payload) {
  const p = parsed.payload;
  const startDate = p.startDate || p.date || p.checkIn || null;
  const endDate   = p.endDate   || p.date || p.checkOut || startDate;
  if (startDate) {
    parsed.endpoint += '&startDate=' + startDate + '&endDate=' + endDate;
  }
}
// Same for listBookings
if (parsed.action === 'beds24.listBookings' && parsed.payload) {
  const p = parsed.payload;
  if (p.startDate || p.date) parsed.endpoint += '&startDate=' + (p.startDate || p.date);
  if (p.endDate)             parsed.endpoint += '&endDate=' + p.endDate;
}
// Append date params for TastyIgniter reservations
if (parsed.action === 'tastyigniter.listReservations' && parsed.payload) {
  const p = parsed.payload;
  const sep = parsed.endpoint.includes('?') ? '&' : '?';
  if (p.startDate) parsed.endpoint += sep + 'startDate=' + p.startDate + '&endDate=' + (p.endDate || p.startDate);
  else if (p.date) parsed.endpoint += sep + 'date=' + p.date;
}
if (parsed.action === 'tastyigniter.checkAvailability' && parsed.payload) {
  const p = parsed.payload;
  const sep = parsed.endpoint.includes('?') ? '&' : '?';
  if (p.date)   parsed.endpoint += sep + 'date=' + p.date;
  if (p.guests) parsed.endpoint += '&guests=' + p.guests;
}


const allowed = {
  admin: ['beds24.getOccupancy','beds24.getPrices','beds24.listBookings','beds24.getRevenue','beds24.blockRoom','beds24.updatePrice','beds24.cancelBooking','tastyigniter.listReservations','tastyigniter.checkAvailability','tastyigniter.deleteReservation','hievents.getTicketCounts','hievents.listEvents','unknown'],
  collaborator: ['beds24.getOccupancy','tastyigniter.listReservations','tastyigniter.checkAvailability','hievents.getTicketCounts','unknown']
};

const nonCommands = ['unknown', 'greeting', 'chitchat', 'small_talk', 'help', 'none'];
if (nonCommands.includes(parsed.action)) {
  const menu = [
    '👋 *Porta D\'irta — Comandos disponibles*',
    '',
    '🏨 *Hotel (Beds24)*',
    '• "¿Cuál es la ocupación de hoy / esta semana?"',
    '• "Lista las reservas de esta semana"',
    '• "¿Cuál es el precio de Torre Badum para el 15 de abril?"',
    '• "Sube Cala Aljub a 160€ del 1 al 15 de junio"',
    '• "Bloquea Ermita Sant Antoni del 1 al 5 de mayo"',
    '',
    '🍽️ *Restaurante (TastyIgniter)*',
    '• "¿Hay reservas de restaurante esta semana?"',
    '• "¿Hay disponibilidad para 4 personas mañana?"',
    '',
    '🎟️ *Eventos (Hi.Events)*',
    '• "¿Cuántas entradas se han vendido?"',
    '',
    '⚠️ *Acciones destructivas* _(piden confirmación)_',
    '• Bloquear habitación',
    '• Actualizar precio',
    '• Cancelar reserva',
  ].join('\n');
  return [{ json: { validationError: menu, chatId: ctx.chatId } }];
}

if (!allowed[ctx.tier]?.includes(parsed.action)) {
  return [{ json: { validationError: `Action '${parsed.action}' not allowed for tier '${ctx.tier}'`, chatId: ctx.chatId } }];
}

if (!parsed.endpoint || !parsed.method) {
  return [{ json: { validationError: 'Gemini missing endpoint or method', chatId: ctx.chatId } }];
}

// Validate payload numeric fields
if (parsed.payload?.price !== undefined && parsed.payload?.price !== null && (isNaN(parsed.payload.price) || parsed.payload.price <= 0)) {
  return [{ json: { validationError: 'Invalid price value in payload', chatId: ctx.chatId } }];
}



// ── Build beds24Payload for updatePrice / blockRoom ──────────────────────
if ((parsed.action === 'beds24.updatePrice' || parsed.action === 'beds24.blockRoom') && parsed.payload) {
  const p = parsed.payload;
  const roomNameMap = {
    'torre badum': 662792, 'torre': 662792,
    'cala el pebret': 662793, 'pebret': 662793,
    'cala aljub': 662794, 'aljub': 662794,
    'ermita sant antoni': 662795, 'ermita': 662795, 'sant antoni': 662795,
  };
  // Claude may put the name in roomId or roomName — handle both
  let numericRoomId = parseInt(p.roomId);
  if (isNaN(numericRoomId)) {
    const key = (p.roomId || p.roomName || '').toLowerCase().trim();
    numericRoomId = roomNameMap[key] || null;
    if (!numericRoomId) {
      for (const [k, v] of Object.entries(roomNameMap)) {
        if (key.includes(k) || k.includes(key)) { numericRoomId = v; break; }
      }
    }
  }
  // Also resolve roomName for display
  const nameFromId = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
  parsed.payload.resolvedRoomName = nameFromId[numericRoomId] || p.roomId || p.roomName || 'habitación';
  const from = p.startDate || p.date || '';
  const to   = p.endDate   || p.date || from;
  if (numericRoomId && from) {
    if (parsed.action === 'beds24.updatePrice') {
      parsed.beds24Payload = JSON.stringify([{ roomId: numericRoomId, calendar: [{ from, to, price1: parseInt(p.price) }] }]);
    } else {
      parsed.beds24Payload = JSON.stringify([{ roomId: numericRoomId, calendar: [{ from, to, available: 0 }] }]);
    }
  } else {
    return [{ json: { validationError: `No pude identificar la habitación: "${p.roomId || p.roomName}". Usa el nombre completo (Torre Badum, Cala El Pebret, Cala Aljub, Ermita Sant Antoni).`, chatId: ctx.chatId } }];
  }
}
// ─────────────────────────────────────────────────────────────────────────

return [{ json: { ...parsed, isDestructive: false, confirmationMessage: null, chatId: ctx.chatId, tier: ctx.tier, valid: true } }];

