// Audit log — non-fatal: a crash here must never kill the flow
const ctx = items[0].json;
let actionCtx = {};
try { actionCtx = $('Schema Validator').first().json || {}; } catch(e) {}
try {
  const sd = $getWorkflowStaticData('global');
  if (!sd.auditLog) sd.auditLog = [];
  sd.auditLog.push({
    ts: new Date().toISOString(),
    user: actionCtx.tier || ctx.tier || '?',
    action: actionCtx.action || ctx.action || '?',
    result: ctx.error ? 'error' : 'success',
    n8nExecutionId: $execution.id,
  });
  if (sd.auditLog.length > 500) sd.auditLog = sd.auditLog.slice(-500);
} catch(e) {}
// Pass through: use summary from Format Response or fall back to humanReadableSummary
const summary = ctx.summary || actionCtx.humanReadableSummary || '✅ Completado.';
return [{ json: { ...ctx, summary, chatId: ctx.chatId || actionCtx.chatId } }];

const apiResp = items[0].json;
const ctx = $('Schema Validator').first().json;
const action = ctx.action || '';
const today = new Date().toISOString().split('T')[0];
const requestedDate = ctx.payload?.date || ctx.payload?.startDate || today;

let summary = '';

if (action === 'beds24.getOccupancy') {
  const rooms = apiResp.data || [];
  if (!rooms.length) {
    summary = '📊 No se encontraron habitaciones.';
  } else {
    const lines = rooms.map(room => {
      const avail = room.availability || {};
      const todayStatus = avail[requestedDate] ?? avail[today];
      const status = todayStatus === true ? '🟢 Libre' : todayStatus === false ? '🔴 Ocupada' : '❓';
      return `• ${room.name}: ${status}`;
    });
    summary = `📊 Ocupación ${requestedDate === today ? 'hoy' : requestedDate} (${requestedDate}):\n` + lines.join('\n');
  }

} else if (action === 'beds24.getPrices') {
  const rooms = apiResp.data || [];
  const basePrices = {"Torre Badum": {"base": 90, "peak": 120}, "Cala El Pebret": {"base": 110, "peak": 150}, "Cala Aljub": {"base": 110, "peak": 150}, "Ermita Sant Antoni": {"base": 130, "peak": 180}};
  const requestedDate = ctx.payload?.date || ctx.payload?.startDate || today;
  const lines = rooms.map(room => {
    const avail = room.availability || {};
    const free = avail[requestedDate] !== false;
    const p = basePrices[room.name] || {};
    const status = free ? '🟢 Libre' : '🔴 Ocupada';
    const price = p.base ? `${p.base}–${p.peak}€/noche` : 'consultar';
    return `• ${room.name}: ${status} | ${price}`;
  });
  const dateLabel = requestedDate === today ? 'hoy' : requestedDate;
  summary = `💰 Precios habitaciones (${dateLabel}):\n` + lines.join('\n') + `\n\nℹ️ Precios orientativos temporada baja–alta.`;

} else if (action === 'beds24.listBookings') {
  const bookings = apiResp.data || [];
  if (!bookings.length) {
    summary = '📋 No hay reservas.';
  } else {
    const roomNames = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
    const channelEmoji = (ch) => ch === 'bookingdotcom' ? '🌐 Booking' : ch === 'airbnb' ? '🏠 Airbnb' : '✉️ Directo';
    const lines = bookings.slice(0, 10).map(b => {
      const name = [b.firstName, b.lastName].filter(Boolean).join(' ') || b.email || '(sin nombre)';
      const room = roomNames[b.roomId] || `Hab.${b.roomId}`;
      const price = b.price ? `${b.price}€` : '';
      const ch = channelEmoji(b.channel || '');
      return `• ${name} | ${room} | ${b.arrival} → ${b.departure} | ${b.numAdult}👤 ${price ? '| '+price : ''} | ${ch}`;
    });
    summary = `📋 Reservas (${bookings.length} total):\n` + lines.join('\n');
    if (bookings.length > 10) summary += `\n... y ${bookings.length - 10} más`;
  }

} else if (action === 'tastyigniter.listReservations') {
  const resos = apiResp.data || [];
  if (!resos.length) {
    summary = '🍽️ No hay reservas de restaurante.';
  } else {
    const lines = resos.slice(0, 10).map(r => {
      const name = [r.first_name, r.last_name].filter(Boolean).join(' ') || '(sin nombre)';
      return `• ${name} | ${r.reserve_date} ${r.reserve_time} | ${r.guest_num} pers.`;
    });
    summary = `🍽️ Reservas restaurante (${resos.length} total):\n` + lines.join('\n');
  }


} else if (action === 'beds24.blockRoom') {
  const results = Array.isArray(apiResp) ? apiResp : [apiResp];
  const ok = results.every(r => r.success === true);
  const p = ctx.payload || {};
  const from = p.startDate || p.date || '?';
  const to   = p.endDate   || p.date || from;
  const roomName = p.roomName || `Habitación ${p.roomId || ''}`;
  summary = ok
    ? `🔒 *${roomName}* bloqueada del ${from} al ${to}.\nNo se aceptarán nuevas reservas en esas fechas.`
    : `❌ Error al bloquear fechas: ${JSON.stringify(results).slice(0,100)}`;

} else if (action === 'beds24.updatePrice') {
  const p = ctx.payload || {};
  const from = p.startDate || p.date || '?';
  const to   = p.endDate   || p.date || from;
  let resolved = ''; try { resolved = $('Build Beds24 Payload v2').first().json.resolvedRoomName || ''; } catch(e) {}
  const roomName = resolved || p.resolvedRoomName || p.roomName || p.roomId || 'habitación';
  const price = p.price || '?';
  // Detect error: HTTP error object from continueOnFail, or explicit success:false
  const hasError = apiResp.error || apiResp.httpCode >= 400 || 
                   (Array.isArray(apiResp) && apiResp.some(r => r.success === false)) ||
                   (!Array.isArray(apiResp) && apiResp.success === false);
  if (hasError) {
    const rawErr = apiResp.message || apiResp.error || apiResp;
    const errMsg = typeof rawErr === 'string' ? rawErr : JSON.stringify(rawErr);
    summary = `❌ Error al actualizar precio ${roomName}: ${errMsg.slice(0,200)}`;
  } else {
    summary = `💰 Precio actualizado: ${roomName} → ${price}€/noche (${from} al ${to})`;
  }
} else if (action === 'beds24.blockRoom') {
  const p = ctx.payload || {};
  const from = p.startDate || p.date || '?';
  const to   = p.endDate   || p.date || from;
  const roomName = p.resolvedRoomName || p.roomName || p.roomId || 'habitación';
  const hasError = apiResp.error || apiResp.httpCode >= 400 ||
                   (Array.isArray(apiResp) && apiResp.some(r => r.success === false)) ||
                   (!Array.isArray(apiResp) && apiResp.success === false);
  if (hasError) {
    const errMsg = apiResp.message || apiResp.error || JSON.stringify(apiResp);
    summary = `❌ Error al bloquear ${roomName}: ${String(errMsg).slice(0,120)}`;
  } else {
    summary = `🔒 *${roomName}* bloqueada del ${from} al ${to}.\nNo se aceptarán nuevas reservas en esas fechas.`;
  }
} else if (action === 'hievents.getTicketCounts' || action === 'hievents.listEvents') {
  const events = apiResp.data || [];
  if (!events.length) {
    summary = '🎟️ No hay eventos activos.';
  } else {
    const lines = events.slice(0, 5).map(ev =>
      `• ${ev.title || ev.name}: ${ev.tickets_sold || 0} vendidos / ${ev.capacity || '?'} cap.`
    );
    summary = `🎟️ Eventos:\n` + lines.join('\n');
  }

} else if (action === 'tastyigniter.checkAvailability') {
  summary = apiResp.available
    ? `✅ Hay disponibilidad para la fecha/hora solicitada.`
    : `❌ No hay disponibilidad para esa fecha/hora.`;

} else {
  // Generic fallback — show raw success/error
  summary = apiResp.success === false
    ? `❌ Error: ${apiResp.error || JSON.stringify(apiResp).slice(0, 200)}`
    : `✅ ${ctx.humanReadableSummary || 'Completado.'}\n\n${JSON.stringify(apiResp).slice(0, 300)}`;
}

return [{ json: { ...ctx, apiResponse: apiResp, summary, chatId: ctx.chatId } }];

const token = items[0].json.token;

let src;
try {
  const sv = $('Schema Validator').first().json;
  if (sv && sv.endpoint) src = sv;
} catch(e) {}

if (!src) {

// Override endpoint for Beds24 calendar actions — route through TastyIgniter PHP proxy
// (n8n HTTP Request node cannot send raw JSON arrays; PHP proxy builds the correct structure)
if (src.action === 'beds24.updatePrice' || src.action === 'beds24.blockRoom') {
  src.endpoint = 'https://restaurant.hobbitonranch.com/api/internal/beds24/calendar';
  src.method   = 'POST';
}

return [{ json: { error: 'No execution context found', chatId: items[0].json.chatId || '' } }];
}

// Build Beds24 calendar API payload here (Schema Validator can't reliably persist it)
let beds24Payload = src.beds24Payload || null;

if (!beds24Payload && (src.action === 'beds24.updatePrice' || src.action === 'beds24.blockRoom') && src.payload) {
  const p = src.payload;
  const roomNameMap = {
    'torre badum': 662792, 'torre': 662792,
