// Merge token (from Refresh node) with endpoint/method/payload
// from either Schema Validator (direct command) or Handle Confirm/Cancel (button click)
const token = items[0].json.token;

let src;
try {
  const sv = $('Schema Validator').first().json;
  if (sv && sv.endpoint) src = sv;
} catch(e) {}

if (!src) {
  try {
    const hcc = $('Handle Confirm/Cancel').first().json;
    if (hcc && hcc.endpoint) src = hcc;
  } catch(e) {}
}

if (!src) {
  return [{ json: { error: 'No execution context found', chatId: items[0].json.chatId || '' } }];
}

return [{ json: {
  token,
  action:        src.action,
  endpoint:      src.endpoint,
  method:        src.method,
  payload:       src.payload,
  beds24Payload: src.beds24Payload || null,
  chatId:        src.chatId || $('Identity Router').first().json.chatId || '',
} }];
